Steps:
[AUTH role=ORG_USER]
[GQL-OP setup_me]
  query { me { id } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-OP cleanup_pre]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD" cultureName: "en-US" }) { id } }
[GQL-EXEC cleanup_pre]
[GQL-OP add_item]
  mutation {
    addItem(command: {
      storeId: "{{STORE_ID}}"
      cartName: "default"
      userId: "{{USER_ID}}"
      currencyCode: "USD"
      cultureName: "en-US"
      productId: "{{PRODUCT_ID}}"
      quantity: 1
    }) {
      id itemsCount
    }
  }
[GQL-EXEC add_item]
[GQL-OP get_line_id]
  query {
    cart(storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD" cultureName: "en-US") {
      itemsCount
      items { id sku productId quantity }
    }
  }
[GQL-EXEC get_line_id]
[GQL-CAPTURE get_line_id.data.cart.items[?productId={{PRODUCT_ID}}].id → LINE_ITEM_ID]
[GQL-OP change_to_overstock]
  mutation {
    changeCartItemQuantity(command: {
      storeId: "{{STORE_ID}}"
      userId: "{{USER_ID}}"
      lineItemId: "{{LINE_ITEM_ID}}"
      quantity: {{OVER_STOCK_QTY}}
    }) {
      id itemsCount
    }
  }
[GQL-EXEC change_to_overstock]
[GQL-OP read_back]
  query {
    cart(storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD" cultureName: "en-US") {
      itemsCount
      items {
        id
        sku
        quantity
        isValid
        validationErrors { errorCode objectType errorMessage }
      }
    }
  }
[GQL-EXEC read_back]
[GQL-OP cleanup_post]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD" cultureName: "en-US" }) { id } }
[GQL-EXEC cleanup_post]

